using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    SummarizeResponse Summarize(SummarizeRequest request);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "it", "its",
        "this", "that", "these", "those", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would",
        "could", "should", "may", "might", "shall", "can", "not", "no",
        "he", "she", "they", "we", "you", "i", "me", "him", "her",
        "us", "them", "my", "your", "his", "our", "their", "which",
        "who", "whom", "what", "where", "when", "how", "if", "then",
        "so", "than", "too", "very", "just", "about", "above", "also"
    };

    public SummarizeResponse Summarize(SummarizeRequest request)
    {
        var sentences = SplitSentences(request.Text);

        if (sentences.Count == 0)
        {
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalSentenceCount = 0,
                SummarySentenceCount = 0
            };
        }

        int take = Math.Min(request.MaxSentences, sentences.Count);

        if (take >= sentences.Count)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        // Build word-frequency map (excluding stop words)
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
                }
            }
        }

        // Score each sentence
        var scored = sentences
            .Select((text, index) => new
            {
                Text = text,
                Index = index,
                Score = Tokenize(text)
                    .Where(w => wordFrequency.ContainsKey(w))
                    .Sum(w => wordFrequency[w])
            })
            .ToList();

        // Pick top sentences, then restore original order
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(take)
            .OrderBy(s => s.Index)
            .Select(s => s.Text);

        var summary = string.Join(" ", topIndices);

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = take
        };
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static IEnumerable<string> Tokenize(string sentence)
    {
        return WordRegex()
            .Matches(sentence)
            .Select(m => m.Value.ToLowerInvariant());
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummaryController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = _summarizer.Summarize(request);
        return Ok(result);
    }
}

